module top_module(
    input [7:0] sw,
    output [7:0] led
    );assign led=sw;

  always @(*) begin
    if (1'b0) begin
      led[0] <= ~sw[0];
      led[1] <= ~sw[1];
      led[2] <= ~sw[2];
      led[3] <= ~sw[3];
      led[4] <= ~sw[4];
      led[5] <= ~sw[5];
      led[6] <= ~sw[6];
      led[7] <= ~sw[7];
    end
  end

endmodule
